"import os\nimport glob\nimport json\n\nbrain_dir = r\"C:\\Users\\mdasw\\.gemini\\antigravity-ide\"\n# Search in all directories under antigravity-ide recursively\nlog_files = glob.glob(os.path.join(brain_dir, \"**\", \"transcript.jsonl\"), recursive=True)\n\nprint(f\"Searching {len(log_files)} log files recursively...\")\n\nmatches_found = 0\nfor lf in log_files:\n    try:\n        with open(lf, 'r', encoding='utf-8', errors='ignore') as f:\n            for idx, line in enumerate(f):\n                if any(x in line for x in ['/admin/attendance', 'def admin_attendance', 'def admin_leaves']):\n                    # Parse JSON line\n                    try:\n                        data = json.loads(line)\n                        content = data.get(\"content\", \"\")\n                        # Check if this content has code snippets\n                        if \"@app.route('/admin/attendance')\" in content or \"def admin_attendance\" in content or \"def admin_leaves\" in content:\n                            print(f\"\\n==========================================\")\n                            print(f\"FOUND MATCH IN: {lf} at line {idx+1}\")\n                            print(f\"==========================================\")\n                            print(content[:3000]) # Print first 3000 chars of code snippet\n                            print(\"==========================================\\n\")\n                            matches_found += 1\n                            if matches_found >= 5:\n                                break\n                    except Exception:\n                        pass\n            if matches_found >= 5:\n                break\n    except Exception as e:\n        print(f\"Error reading {lf}: {e}\")\n\nprint(f\"Search complete. Found {matches_found} candidate match blocks.\")\n"